package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void registerTypeAdapterFactory_nullFactory_throwsNullPointerException() {
    NullPointerException exception = assertThrows(NullPointerException.class, () -> {
      gsonBuilder.registerTypeAdapterFactory(null);
    });
    assertEquals("factory is marked non-null but is null", exception.getMessage(), 
      "Exception message should indicate null factory");
  }

  @Test
  public void registerTypeAdapterFactory_addsFactoryToFactoriesList() throws Exception {
    TypeAdapterFactory factoryMock = mock(TypeAdapterFactory.class);

    GsonBuilder returned = gsonBuilder.registerTypeAdapterFactory(factoryMock);

    assertSame(gsonBuilder, returned, "Method should return the same GsonBuilder instance");

    // Use reflection to get the private 'factories' field
    Field factoriesField = GsonBuilder.class.getDeclaredField("factories");
    factoriesField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<TypeAdapterFactory> factories = (List<TypeAdapterFactory>) factoriesField.get(gsonBuilder);

    assertTrue(factories.contains(factoryMock), "Factories list should contain the registered factory");
  }

}
